function initMap(){if(!window.L)throw Error('Leaflet map library failed to load.');const container=$('map');map=L.map(container,{zoomControl:true,preferCanvas:true}).setView([52.4,-1.5],6);L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:19,attribution:'&copy; OpenStreetMap contributors',crossOrigin:'anonymous',updateWhenIdle:true,keepBuffer:3}).addTo(map);L.control.scale({imperial:false}).addTo(map);map.on('click',e=>setSite(e.latlng.lat,e.latlng.lng,'Map-selected site'));const refresh=()=>requestAnimationFrame(()=>map.invalidateSize({pan:false,animate:false}));if('ResizeObserver'in window)new ResizeObserver(refresh).observe(container);window.addEventListener('resize',refresh,{passive:true});setTimeout(refresh,0);setTimeout(refresh,250);log('map-initialised',{engine:'Leaflet 1.9.4',dragging:map.dragging.enabled(),zoom:map.scrollWheelZoom.enabled()})}
function setSite(lat,lon,label){site={lat:+lat,lon:+lon,label};confirmed=false;$('run').disabled=true;$('confirm').disabled=false;$('returnSite').disabled=false;$('fitAssessment').disabled=false;$('siteState').className='badge warn';$('siteState').textContent='Check marker';$('siteLabel').textContent=label;$('coordLabel').textContent=`${site.lat.toFixed(6)}, ${site.lon.toFixed(6)}`;$('lat').value=site.lat.toFixed(6);$('lon').value=site.lon.toFixed(6);siteMarker?.remove();siteMarker=L.marker([site.lat,site.lon],{draggable:true,icon:icon('site-dot')}).addTo(map);siteMarker.on('dragend',e=>{const p=e.target.getLatLng();setSite(p.lat,p.lng,'Adjusted site')});map.setView([site.lat,site.lon],15);log('site-selected',site)}
async function geocode(){const q=$('address').value.trim();if(!q)return;try{const u=`https://nominatim.openstreetmap.org/search?format=jsonv2&countrycodes=gb&limit=5&q=${encodeURIComponent(q)}`,data=await timed(12000,s=>fetch(u,{signal:s,headers:{Accept:'application/json'}}).then(r=>{if(!r.ok)throw Error(`HTTP ${r.status}`);return r.json()}));$('matches').innerHTML=data.map((x,i)=>`<button data-i="${i}">${esc(x.display_name)}</button>`).join('');$('matches').hidden=!data.length;$('matches').querySelectorAll('button').forEach(b=>b.onclick=()=>{const x=data[+b.dataset.i];setSite(x.lat,x.lon,x.display_name);$('matches').hidden=true});log('address-lookup',{query:q,count:data.length})}catch(e){show(`Address lookup failed: ${e.message}`,true);log('address-failed',{error:e.message})}}
function query(radius){return`[out:json][timeout:25];(nwr["railway"~"^(station|halt|tram_stop)$"](around:${radius},${site.lat},${site.lon});nwr["station"~"^(subway|light_rail)$"](around:${radius},${site.lat},${site.lon});nwr["public_transport"="station"]["train"="yes"](around:${radius},${site.lat},${site.lon});nwr["public_transport"="station"]["subway"="yes"](around:${radius},${site.lat},${site.lon});nwr["public_transport"="station"]["light_rail"="yes"](around:${radius},${site.lat},${site.lon});nwr["public_transport"="station"]["network"~"National Rail|London Underground|London Overground|Docklands Light Railway|DLR",i](around:${radius},${site.lat},${site.lon}););out center tags;`}
async function overpass(q){const failures=[];for(const endpoint of endpoints){const start=performance.now();try{const x=await timed(18000,s=>fetch(endpoint,{method:'POST',signal:s,headers:{'Content-Type':'application/x-www-form-urlencoded'},body:`data=${encodeURIComponent(q)}`}).then(r=>{if(!r.ok)throw Error(`HTTP ${r.status}`);return r.json()}));log('overpass-success',{endpoint,ms:Math.round(performance.now()-start),elements:x.elements?.length||0,priorFailures:failures});return x.elements||[]}catch(e){failures.push({endpoint,ms:Math.round(performance.now()-start),error:e.name==='AbortError'?'timeout':e.message});log('overpass-attempt-failed',failures.at(-1))}}throw Error('All station-data endpoints failed. This is a request failure, not a zero-station result.')}
