async function pool(items,limit,fn){let i=0;async function w(){while(i<items.length){const n=i++;await fn(items[n],n)}}await Promise.all(Array.from({length:Math.min(limit,items.length)},w))}
async function run(){if(!confirmed)return;const radius=Math.max(.5,Math.min(30,+$('radius').value||5))*1000,max=Math.max(1,Math.min(50,+$('maxStations').value||20));$('run').disabled=true;$('searchState').textContent='Running';$('searchState').className='badge warn';$('progress').hidden=false;try{$('progressText').textContent='Downloading mapped stations…';$('barFill').style.width='15%';stations=parse(await overpass(query(radius)),radius).slice(0,max);if(!stations.length){show('The request succeeded, but no mapped stations were found within the selected radius.');$('results').hidden=true;return}$('progressText').textContent=`Routing ${stations.length} stations…`;$('barFill').style.width='40%';await pool(stations,3,async(s,i)=>{[s.walk,s.cycle]=await Promise.all([route(s,'walk'),route(s,'cycle')]);const saved=matchRecord(library,s);s.record=saved?structuredClone(saved):makeRecord(s);s.include=true;$('barFill').style.width=`${40+Math.round((i+1)/stations.length*55)}%`});render();draw();$('results').hidden=false;$('barFill').style.width='100%';$('progressText').textContent='Assessment complete.';$('searchState').textContent='Complete';$('searchState').className='badge good';show(`${stations.length} station${stations.length===1?'':'s'} found and assessed.`);log('assessment-complete',{stations:stations.length})}catch(e){show(e.message,true);$('searchState').textContent='Failed';$('searchState').className='badge bad';log('assessment-failed',{error:e.message})}finally{$('run').disabled=false;setTimeout(()=>map.invalidateSize(),100)}}
