function rebuildEffectiveRail(){const effective={},stats={preserved:0,conflicts:0,updated:0};sharedRecords.forEach(record=>upsert(effective,record,stats));Object.values(localLibrary).forEach(record=>upsert(effective,record,stats));library=effective;sharedRail.conflicts=stats.conflicts;sharedRail.matches=stations.filter(st=>matchRecord(library,st)).length;stations.forEach(st=>{const record=matchRecord(library,st);if(record)st.record=structuredClone(record)});return stats}
function saveStation(st,card){st.record.name=st.name;st.record.canonicalName=st.name;st.record.mode=st.mode;st.record.coordinates={lat:st.lat,lon:st.lon};st.record.identifiers={crs:st.crs,naptan:st.naptan,tfl:st.tfl,other:st.otherIdentifier,osm:st.osmId};const result=upsert(localLibrary,st.record,{preserved:0,conflicts:0,updated:0});if(st.include)railPublishSelected.add(result.record.key);saveLibrary(localLibrary);rebuildEffectiveRail();st.record=structuredClone(matchRecord(library,st)||result.record);updateKnowledge();sharedStatus();renderSources();const text=`Saved to the local Rail overlay at ${new Date().toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'})}.`;card.querySelector('.station-save-status').textContent=text;show(`${st.name}: ${text}`)}
function coordText(x){return `${Number(x.lat).toFixed(6)}, ${Number(x.lon).toFixed(6)}`};function mapsUrl(x){return `https://www.google.com/maps/search/?api=1&query=${Number(x.lat).toFixed(7)},${Number(x.lon).toFixed(7)}`};async function copyCoords(x,b){await navigator.clipboard.writeText(coordText(x));b.textContent='Coordinates copied';setTimeout(()=>b.textContent='Copy coordinates',1800)}
