new MutationObserver(()=>document.querySelectorAll('.station').forEach(card=>{if(card.querySelector('.verify-actions'))return;const s=stations[+card.dataset.i],head=card.querySelector('.station-head');if(!s||!head)return;const box=document.createElement('div');box.className='verify-actions';box.innerHTML=`<a class="button secondary verify-action" href="${mapsUrl(s)}" target="_blank" rel="noopener noreferrer">Open in Google Maps</a><button class="button secondary verify-action">Copy coordinates</button>`;box.querySelector('button').onclick=()=>copyCoords(s,box.querySelector('button'));head.insertAdjacentElement('afterend',box)})).observe($('cards'),{childList:true,subtree:true});
function showRoutes(s,kind='both'){clearRouteLines();const wantsWalk=kind==='walk'||kind==='both',wantsCycle=kind==='cycle'||kind==='both';if(wantsWalk&&s.walk.geometry)routeLayers.push(L.geoJSON(s.walk.geometry,{style:{color:'#176b76',weight:5,opacity:.9}}).addTo(map));if(wantsCycle&&s.cycle.geometry)routeLayers.push(L.geoJSON(s.cycle.geometry,{style:{color:'#b76027',weight:5,opacity:.9}}).addTo(map));$('clearRoutes').disabled=!routeLayers.length;if(routeLayers.length){const group=L.featureGroup(routeLayers);map.fitBounds(group.getBounds().pad(.1));show(`${kind==='both'?'Walking and cycling':kind==='walk'?'Walking':'Cycling'} route shown for ${s.name}.`)}else show(`No routed ${kind==='both'?'walking or cycling':kind} geometry is available for ${s.name}. The displayed distance is an estimate and has not been drawn as a route.`,true)}
function clearRouteLines(){routeLayers.forEach(x=>x.remove());routeLayers=[];$('clearRoutes').disabled=true}
function renderSources(){const rows=[];for(const s of stations){for(const [key,f] of Object.entries(s.record?.fields||{})){if(!f?.source)continue;rows.push(`<tr><td>${esc(s.name)}</td><td>${esc(labels[key]||key)}</td><td class="source-link"><a href="${esc(f.source)}" target="_blank" rel="noopener">${esc(f.sourceTitle||f.source)}</a></td><td>${esc((f.retrievalDate||'Not recorded').slice(0,10))}</td><td>${esc((f.status||'missing').replace('_',' '))}</td></tr>`)}if(s.source)rows.push(`<tr><td>${esc(s.name)}</td><td>Mapped station location</td><td class="source-link"><a href="${esc(s.source)}" target="_blank" rel="noopener">OpenStreetMap feature</a></td><td>Current search</td><td>mapped discovery</td></tr>`)}$('sourcesBody').innerHTML=rows.join('');$('sourcesTable').hidden=!rows.length;$('sourcesEmpty').hidden=!!rows.length}
function selected(){return stations.filter(s=>s.include)}
function railRecordDate(record){return Math.max(0,...Object.values(record.fields||{}).map(field=>Date.parse(field.retrievalDate||'')||0),Date.parse(record.updatedAt||'')||0)}
function railSharedRecord(record){const wanted=keyFor(record);return sharedRecords.find(item=>keyFor(item)===wanted)||null}
function railQuality(record){return TPTResearchQuality.analyseRecord(record,'rail',{allowLegacyEvidence:false})}
function railPrediction(record,quality){if(!quality.publishable)return'Blocked and reason';const shared=railSharedRecord(record);if(!shared)return'Ready to add';const newerVerified=railRecordDate(shared)>railRecordDate(record)&&Object.values(shared.fields||{}).some(field=>TPTResearchQuality.statusClass(field.status)==='verified');return newerVerified?'Existing record preserved':'Ready to update'}
function renderRailPublishPreview(){const groups={'Ready to add':[],'Ready to update':[],'Existing record preserved':[],'Blocked and reason':[],'Not selected':[]};Object.values(localLibrary).forEach(record=>{const quality=railQuality(record),chosen=railPublishSelected.has(record.key),prediction=railPrediction(record,quality),label=`${record.name||record.canonicalName} (${record.key})${quality.publishable?'':` — ${quality.publicationBlockers[0]?.reason||quality.quality}`}`;groups[chosen?prediction:'Not selected'].push(label)});const panel=$('railPublishPreview'),content=Object.entries(groups).map(([heading,items])=>`<section><h4>${heading} (${items.length})</h4>${items.length?`<ul>${items.map(item=>`<li>${esc(item)}</li>`).join('')}</ul>`:'<p>None</p>'}</section>`).join('');panel.hidden=!Object.keys(localLibrary).length;panel.innerHTML=`<h3>Rail publication preview</h3>${content}`}
function renderRailProposals(){const records=Object.values(localLibrary);if(!railSelectionTouched)selected().forEach(st=>{const match=matchRecord(localLibrary,st);if(st.include&&match&&railQuality(match).publishable)railPublishSelected.add(match.key)});railPublishSelected=new Set([...railPublishSelected].filter(key=>localLibrary[key]));const list=$('railProposalList');list.innerHTML=records.length?records.sort((a,b)=>(a.name||'').localeCompare(b.name||'')).map(record=>{const quality=railQuality(record),blocked=!quality.publishable,reason=blocked?(quality.publicationBlockers[0]?.reason||quality.quality):railPrediction(record,quality);return`<label class="rail-proposal"><input type="checkbox" data-rail-publish-key="${esc(record.key)}" ${railPublishSelected.has(record.key)?'checked':''} ${blocked?'disabled':''}><span><strong>${esc(record.name||record.canonicalName)}</strong> · ${esc(record.key)}<small>${esc(quality.quality)} · ${esc(reason)}</small></span></label>`}).join(''):'<p class="note">No local Rail proposals are stored in this browser.</p>';list.querySelectorAll('[data-rail-publish-key]').forEach(box=>box.onchange=()=>{railSelectionTouched=true;box.checked?railPublishSelected.add(box.dataset.railPublishKey):railPublishSelected.delete(box.dataset.railPublishKey);renderRailPublishPreview();sharedStatus()});renderRailPublishPreview()}
function download(name,data,type='application/json'){const a=document.createElement('a'),u=URL.createObjectURL(new Blob([data],{type}));a.href=u;a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(u),1000)}
function freqByDestinationText(f){return Array.isArray(f?.value)?f.value.map(x=>`${x.tph??'—'} tph ${x.destination}${x.qualifier?` (${x.qualifier})`:''}`).join('; '):''}
function tableRows(){return selected().map(s=>[s.name,s.mode,s.record.fields.lines.value,fmtM(s.walk.distance),fmtT(s.walk.duration),s.walk.status,fmtM(s.cycle.distance),fmtT(s.cycle.duration),s.cycle.status,s.record.fields.manager.value,s.record.fields.operators.value,s.record.fields.frequencyTotal.value,freqByDestinationText(s.record.fields.frequencyByDestination),s.record.fields.destinations.value,s.record.fields.cycleParking.value,s.record.fields.stepFree.value])}
function exportCsv(){const h=['Station','Mode','Line(s)','Walking distance','Walking time','Walking basis','Cycling distance','Cycling time','Cycling basis','Manager','Operators','Typical total weekday TPH','Typical TPH by destination/direction','Principal destinations','Cycle parking','Step-free access'],q=v=>`"${String(v??'').replaceAll('"','""')}"`;download('railway-assessment.csv',[h,...tableRows()].map(r=>r.map(q).join(',')).join('\n'),'text/csv')}
function stepFreeMark(value){const text=String(value??'').trim().toLowerCase();return /^(no|none|not available|false)|not step[- ]?free|no step[- ]?free/.test(text)?'\u2717':text?'\u2713':'\u2717'}
function serviceSummary(s){const f=s.record.fields,parts=[];if(f.servicePattern.value)parts.push(`Service pattern: ${f.servicePattern.value}`);if(f.journeyOpportunities.value)parts.push(`Journey opportunities: ${f.journeyOpportunities.value}`);return parts.length?`${s.name} - ${parts.join(' | ')}`:`${s.name} - Service pattern and journey opportunities not yet recorded.`}
function railwayWordTables(){const accessRows=selected().map(s=>[s.name,s.mode,`${fmtM(s.walk.distance)}${s.walk.status==='estimated'?' (estimated)':''}`,`${fmtT(s.walk.duration)}${s.walk.status==='estimated'?' (estimated)':''}`,`${fmtM(s.cycle.distance)}${s.cycle.status==='estimated'?' (estimated)':''}`,`${fmtT(s.cycle.duration)}${s.cycle.status==='estimated'?' (estimated)':''}`]);const serviceRows=[];for(const s of selected()){const f=s.record.fields;serviceRows.push([s.name,f.manager.value,f.operators.value,f.lines.value,freqByDestinationText(f.frequencyByDestination)||f.frequencyTotal.value,f.destinations.value,f.cycleParking.value,stepFreeMark(f.stepFree.value)]);serviceRows.push({kind:'summary',text:serviceSummary(s)})}return[{caption:'Table X.X - Railway Station Access Summary',headers:['Station','Mode','Walking distance','Walking time','Cycling distance','Cycling time'],rows:accessRows,widths:[22,18,15,15,15,15]},{caption:'Table X.X - Railway Service Summary',headers:['Station','Station manager','Train operators','Railway lines','Typical weekday trains per hour by direction','Principal direct destinations served','Cycle storage','Step-free access'],rows:serviceRows,widths:[11,12,12,12,17,17,10,9]}]}
function railwayTphTables(){return selected().map(s=>{const rows=(s.record.fields.frequencyByDestination.value||[]).filter(x=>x.destination||x.tph!==null&&x.tph!=='').map(x=>[x.destination,x.tph==null||x.tph===''?'—':String(x.tph),x.qualifier||'']);if(!rows.length)rows.push(['Not yet recorded','—','Complete the directional TPH section in the station record.']);return{caption:`Table X.X - ${s.name}: Typical Weekday Trains per Hour by Direction`,headers:['Direction / destination','TPH','Service note'],rows,widths:[45,15,40]}})}
async function copyTable(){try{await copyWordTables(railwayWordTables());show('EAS-formatted Railway tables copied for Word.')}catch(e){show(`${e.message} Use Download Word tables instead.`,true)}}
function downloadWordTables(){wording();downloadWordDocument('railway-assessment-tables.docx','Railway Assessment Tables',railwayWordTables(),$('wording').value)}
function downloadTphTables(){downloadWordDocument('railway-directional-tph-tables.docx','Railway Directional Trains per Hour',railwayTphTables())}
function wording(){const approved=selected(),access=approved.map(x=>`${x.name} is approximately ${fmtM(x.walk.distance)} from the site by ${x.walk.status==='routed'?'routed':'estimated'} walking route (${fmtT(x.walk.duration)}) and ${fmtM(x.cycle.distance)} by ${x.cycle.status==='routed'?'routed':'estimated'} cycling route (${fmtT(x.cycle.duration)}).`).join('\n\n'),services=approved.map(x=>{const f=x.record.fields,manager=f.manager.value?`${x.name} is managed by ${f.manager.value}. `:'',operators=f.operators.value?`Services are operated by ${f.operators.value}. `:'',freq=f.frequencyTotal.value?`Typical weekday services operate at ${f.frequencyTotal.value}. `:f.frequency.value?`The recorded typical weekday frequency is ${f.frequency.value}. `:'',pattern=f.servicePattern.value?`${f.servicePattern.value} `:'',dest=f.destinations.value?`Direct principal destinations include ${f.destinations.value}. `:'',facilities=[f.cycleParking.value&&`cycle parking: ${f.cycleParking.value}`,f.stepFree.value&&`step-free access: ${f.stepFree.value}`].filter(Boolean);return(manager+operators+freq+pattern+dest+(facilities.length?`Recorded facilities include ${facilities.join('; ')}.`:'')).trim()}).filter(Boolean).join('\n\n'),limits='Sources and limitations\n\nWalking and cycling values retain their routed or estimated status. Service information and operating patterns should be checked against the cited sources and retrieval dates before submission.';$('wording').value=['Access wording',access,'Service wording',services,limits].filter(Boolean).join('\n\n');$('wordingPanel').hidden=false}
let sharedRail={count:0,lastRefresh:'',lastPublication:'',conflicts:0,review:0,matches:0,state:'Loading',schema:'',build:'',source:''};
function sharedStatus(){const connection=window.TPTSharedLibrary?.connection()||{},local=Object.keys(localLibrary).length,effective=Object.keys(library).length;$('sharedRailStatus').innerHTML=`<span><strong>Load state</strong><br>${sharedRail.state}</span><span><strong>Shared Rail records</strong><br>${sharedRail.count}</span><span><strong>Local draft records</strong><br>${local}</span><span><strong>Effective records</strong><br>${effective}</span><span><strong>Assessment matches</strong><br>${sharedRail.matches}</span><span><strong>Conflicts</strong><br>${sharedRail.conflicts}</span><span><strong>Requiring review</strong><br>${sharedRail.review}</span><span><strong>Last master load</strong><br>${sharedRail.lastRefresh||'Not yet'}</span><span><strong>Schema / build</strong><br>${sharedRail.schema||'Not loaded'} · ${sharedRail.build||'Not recorded'}</span><span><strong>Source</strong><br>${sharedRail.source||'Not loaded'}</span><span><strong>Publishing connection</strong><br>${connection.connected?'Connected':'Not connected'}</span><span><strong>Last publication</strong><br>${sharedRail.lastPublication||'Not yet'}</span>`;$('publishShared').disabled=!connection.connected||!local;if(sharedRail.state==='Failed')return;$('sharedPublishMessage').innerHTML=connection.connected?'Shared master reads automatically; Toolkit connection recognised for publishing.':'Shared master reads automatically without a token. To publish, connect on the <a href="../../#shared-library">Dashboard Shared Company Knowledge Library panel</a>.'}
async function refreshSharedRail(){sharedRail.state='Loading';sharedStatus();try{const masters=await window.TPTSharedLibrary.loadAll(),meta=masters.meta?.files?.rail||{};if(meta.source==='failed')throw Error(masters.meta.errors.find(x=>x.name==='rail')?.message||'Rail master failed to load.');sharedRecords=masters.rail.records||[];sharedRail.count=sharedRecords.length;sharedRail.lastRefresh=new Date().toLocaleString();sharedRail.review=sharedRecords.filter(r=>r.reviewFlags?.length||Object.values(r.fields||{}).some(f=>f.status==='needs_review')).length;sharedRail.schema=masters.rail.schema;sharedRail.build=masters.rail.libraryBuild||String(masters.rail.version||'');sharedRail.source=meta.source||'network';sharedRail.state=meta.source==='cache'?'Cached master in use':sharedRail.count?'Loaded':'Loaded successfully — zero records';rebuildEffectiveRail();if(stations.length)render();$('sharedPublishMessage').textContent=`Shared Rail master ${sharedRail.state.toLowerCase()}: ${sharedRail.count} shared, ${Object.keys(localLibrary).length} local and ${Object.keys(library).length} effective records.`}catch(error){sharedRail.state='Failed';$('sharedPublishMessage').textContent='Shared Rail master failed to load: '+error.message}sharedStatus()}
async function publishSharedRail(){const resultPanel=$('railPublishResult');resultPanel.hidden=true;try{const records=[...railPublishSelected].map(key=>localLibrary[key]).filter(Boolean),blocked=records.map(record=>({record,quality:railQuality(record)})).filter(item=>!item.quality.publishable);if(blocked.length)throw Error(`${blocked[0].record.name}: ${blocked[0].quality.publicationBlockers[0]?.reason||'publication blocked'}`);if(!records.length)throw Error('Select at least one eligible saved Rail proposal.');renderRailPublishPreview();$('sharedPublishMessage').textContent=`Publishing ${records.length} deliberately selected Rail proposal(s)…`;const result=await window.TPTSharedLibrary.publishRecords(TPTSharedLibrary.paths.rail,records,BUILD),p=result.preview||{};if(!result.verified)throw Error('The latest GitHub master did not confirm the intended canonical keys.');sharedRail.conflicts=p.conflicts||0;sharedRail.lastPublication=new Date().toLocaleString();await refreshSharedRail();if(!(p.conflicts||p.preserved))records.forEach(record=>{delete localLibrary[record.key];railPublishSelected.delete(record.key)});saveLibrary(localLibrary);rebuildEffectiveRail();updateKnowledge();const names=records.map(record=>`<li>${esc(record.name||record.canonicalName)} · ${esc(record.key)}</li>`).join('');resultPanel.innerHTML=`<h3>Successfully added to the Shared Company Library</h3><ul>${names}</ul><p>Added: ${p.additions||0} · Updated: ${p.updates||0} · Preserved: ${p.preserved||0} · Blocked: 0</p><p>Published ${esc(sharedRail.lastPublication)} · commit ${esc(result.commit||'confirmed')} · latest GitHub master reloaded and exact canonical keys verified.</p>`;resultPanel.hidden=false;$('sharedPublishMessage').textContent=`Publication and post-publication verification succeeded for ${records.length} selected record(s).`}catch(error){$('sharedPublishMessage').textContent='Publication not completed: '+error.message}sharedStatus();renderRailProposals()}
function updateKnowledge(){const s=summary(localLibrary);$('knowledgeStatus').textContent=`${s.count} local draft record${s.count===1?'':'s'} · last review ${s.lastReview?s.lastReview.slice(0,10):'not recorded'}${s.stale?` · ${s.stale} potentially stale`:''}`;const banner=$('unpublishedRailBanner');banner.hidden=!s.count;banner.textContent=`${s.count} UNPUBLISHED RAIL PROPOSAL${s.count===1?'':'S'} — other workstations cannot use ${s.count===1?'this record':'these records'} yet. Review and add eligible selected records to the Shared Company Library.`;renderRailProposals()}
function knowledgeEnvelope(reason='export'){return{schema:KNOWLEDGE_SCHEMA,version:SCHEMA_VERSION,reason,exportedAt:new Date().toISOString(),records:localLibrary}}
function exportResearch(){currentRailPlan();exportRailBatch(TPTResearchWorkflow.nextBatch(railPlan))}
async function importResearchFile(file){const progress=$('railImportProgress'),steps=[];const step=value=>{steps.push(value);progress.textContent=steps.join(' → ')};try{step('File selected');step('Reading JSON');const data=JSON.parse(await file.text());lastRailImport=data;step('Checking schema');if(data.schema!==COMPLETED_SCHEMA||Number(data.version)!==SCHEMA_VERSION)throw Error(`Expected ${COMPLETED_SCHEMA} version ${SCHEMA_VERSION}.`);step('Checking requested identities');validateRequestedRecords(data,selected());step('Checking field evidence');const quality=TPTResearchQuality.validateRailCompleted(data,{reject:false,allowLegacyEvidence:false});lastRailFailures=quality.records.flatMap(report=>report.issues.map(issue=>{const raw=(data.records||[]).find(x=>(completedRecord(x).name||completedRecord(x).canonicalName)===report.record),field=completedRecord(raw||{}).fields?.[issue.field];return{record:issue.record,field:issue.field,reason:issue.reason,url:field?.source||field?.sources?.[0]?.url||''}}));renderRailFailures();if(lastRailFailures.length){const matched=(railPlan?.batches||[]).find(batch=>batch.batchId===(data.batchMetadata||{}).batchId);if(matched)TPTResearchWorkflow.markBatch(railPlan,matched.batchId,'blocked',file.name);persistRailPlan();renderRailPlan();throw Error(`${lastRailFailures.length} field(s) require correction across ${new Set(lastRailFailures.map(x=>x.record)).size} station(s). Download one targeted correction request.`)}step('Preparing import');await importJson(file,'research');const keys=new Set((data.records||[]).map(x=>TPTResearchWorkflow.railKey(completedRecord(x)))),batch=(railPlan?.batches||[]).find(x=>x.batchId===(data.batchMetadata||{}).batchId)|| (railPlan?.batches||[]).find(x=>x.selectedCanonicalRecordKeys.every(key=>keys.has(key)));if(batch)TPTResearchWorkflow.markBatch(railPlan,batch.batchId,'imported',file.name);persistRailPlan();lastRailFailures=[];renderRailFailures();renderRailPlan();step('Import completed');progress.textContent+=` — ${data.records.length} station(s) accepted; full field evidence passed.`}catch(error){step('Import blocked');progress.textContent+=` — ${error.message}`;throw error}}
async function importJson(file,kind){const data=JSON.parse(await file.text());if(kind==='knowledge')validateKnowledge(data);else{validateCompleted(data);validateRequestedRecords(data,selected())}localStorage.setItem('tpt.rail.knowledge.backup.v3',JSON.stringify(knowledgeEnvelope(`before-${kind}-import`)));const incoming=Array.isArray(data.records)?data.records:Object.values(data.records),totals={added:0,updated:0,preserved:0,conflicts:0,rejected:0};for(const raw of incoming){try{const r=kind==='research'?completedRecord(raw):(raw.record||raw),m=matchRecord(library,r);if(kind==='research'&&!m&&!r.identifiers?.crs&&!r.identifiers?.tfl&&!r.identifiers?.naptan&&!r.identifiers?.osm){totals.rejected++;continue}const stats={preserved:0,conflicts:0,updated:0},result=upsert(localLibrary,r,stats);totals.added+=result.added?1:0;totals.updated+=result.added?0:1;totals.preserved+=stats.preserved;totals.conflicts+=stats.conflicts}catch{totals.rejected++}}saveLibrary(localLibrary);rebuildEffectiveRail();if(stations.length)render();updateKnowledge();sharedStatus();show(`Import complete — added: ${totals.added}; updated: ${totals.updated}; fields preserved: ${totals.preserved}; conflicts: ${totals.conflicts}; rejected: ${totals.rejected}.`,totals.rejected>0)}
function loadProject(){try{const p=JSON.parse(localStorage.getItem(PROJECT_KEY)||'{}');const addr=p.siteAddress||p.address||p.projectAddress||'';$('address').value=addr;const lat=+(p.latitude??p.lat),lon=+(p.longitude??p.lon??p.lng);if(Number.isFinite(lat)&&Number.isFinite(lon))setSite(lat,lon,addr||'Stored project site')}catch(e){log('project-prefill-failed',{error:e.message})}}
$('locate').onclick=geocode;$('address').onkeydown=e=>{if(e.key==='Enter')geocode()};$('useCoords').onclick=()=>{const a=+$('lat').value,o=+$('lon').value;if(Number.isFinite(a)&&Number.isFinite(o))setSite(a,o,'Coordinate input')};$('confirm').onclick=()=>{confirmed=true;$('run').disabled=false;$('siteState').textContent='Confirmed';$('siteState').className='badge good';localStorage.setItem(PROJECT_KEY,JSON.stringify({...JSON.parse(localStorage.getItem(PROJECT_KEY)||'{}'),siteAddress:$('siteLabel').textContent,latitude:site.lat,longitude:site.lon}))};$('run').onclick=async()=>{await sharedLoadPromise;return run()};$('csvBtn').onclick=exportCsv;$('copyBtn').onclick=copyTable;$('downloadWordBtn').onclick=downloadWordTables;$('wordingBtn').onclick=wording;$('copyWording').onclick=()=>navigator.clipboard.writeText($('wording').value);$('saveBtn').onclick=()=>{localStorage.setItem(SAVE_KEY,JSON.stringify({build:BUILD,site,stations,savedAt:new Date().toISOString()}));show('Assessment saved in this browser.')};$('diagBtn').onclick=()=>$('diag').showModal();$('closeDiag').onclick=()=>$('diag').close();$('exportKnowledge').onclick=()=>download('rail-knowledge-library.json',JSON.stringify(knowledgeEnvelope(),null,2));$('backupKnowledge').onclick=()=>download('rail-knowledge-backup.json',JSON.stringify(knowledgeEnvelope('manual-backup'),null,2));$('importKnowledge').onchange=async e=>{try{if(e.target.files[0])await importJson(e.target.files[0],'knowledge')}catch(x){show(x.message,true)}e.target.value=''};$('importResearch').onchange=async e=>{try{if(e.target.files[0])await importJson(e.target.files[0],'research')}catch(x){show(x.message,true)}e.target.value=''};$('exportResearch').onclick=exportResearch;$('publishShared').onclick=publishSharedRail;$('refreshShared').onclick=()=>{sharedLoadPromise=refreshSharedRail()};$('clearKnowledge').onclick=()=>{if(confirm('A backup will be created before clearing. Continue?')){localStorage.setItem('tpt.rail.knowledge.backup.v3',JSON.stringify(knowledgeEnvelope('before-clear')));localLibrary={};saveLibrary(localLibrary);rebuildEffectiveRail();updateKnowledge();sharedStatus();show('Local Rail overlay cleared; shared master records remain available.')}};
document.querySelectorAll('.tab').forEach(button=>button.onclick=()=>{document.querySelectorAll('.tab').forEach(x=>{const active=x===button;x.classList.toggle('active',active);x.setAttribute('aria-selected',String(active))});document.querySelectorAll('.tab-page').forEach(page=>{const active=page.dataset.page===button.dataset.tab;page.classList.toggle('active',active);page.hidden=!active});if(button.dataset.tab==='assessment')setTimeout(()=>map.invalidateSize(),50);if(button.dataset.tab==='sources')renderSources()});
function railStep(state,label,detail){return`<li class="${state}"><span class="state">${state==='complete'?'✓ COMPLETE':state==='next'?'→ DO THIS NEXT':state==='correction'?'! CORRECTION REQUIRED':'○ WAITING'}</span><strong>${esc(label)}</strong>${detail?`<br>${esc(detail)}`:''}</li>`}
function renderRailPlan(){const plan=currentRailPlan(),next=TPTResearchWorkflow.nextBatch(plan),imported=plan.batches.filter(x=>x.status==='imported').length,partial=plan.batches.find(x=>x.status==='correction-required'),primary=$('railPrimaryAction');let action='none',label='Select stations in the assessment';if(!plan.selectedCount){primary.disabled=true}else if(partial&&lastRailFailures.length){action='correction';label='Download corrections for '+partial.failedKeys.length+' station(s)';primary.disabled=false}else if(next?.status==='exported'){action='import';label='Import completed station research';primary.disabled=false}else if(next){action='export';label='Download research request '+next.batchNumber+' of '+next.totalPlannedBatches;primary.disabled=false}else{action='review';label='Review existing and completed station information';primary.disabled=false}primary.dataset.action=action;primary.textContent=label;const researchState=!plan.selectedCount?'waiting':partial?'correction':next?'next':'complete',publishState=!plan.selectedCount||next?'waiting':'next';$('railBatchPlan').innerHTML=`<p><strong>${plan.selectedCount} station(s); ${plan.reusedCount} complete Shared Library record(s) reused; ${plan.researchCount} targeted research task(s); ${imported} of ${plan.batches.length} pack(s) complete</strong></p><ol class="guided-research">${railStep(plan.selectedCount?'complete':'next','Select stations',plan.selectedCount?plan.selectedCount+' selected':'Use the assessment first')}${railStep(researchState,partial?'Correct the remaining station research':next?'Complete targeted research pack '+next.batchNumber:'No new station research required',!plan.selectedCount?'Available after station selection.':partial?`${partial.passedKeys.length} passed; ${partial.failedKeys.length} still need correction`:next?.status==='exported'?'Attach the downloaded file to ChatGPT, then import the result.':next?'Only missing or stale fields are requested.':'Existing company information is ready for review.')}${railStep(publishState,'Review and publish eligible proposals',next||!plan.selectedCount?'Available after required research passes':'Only complete, evidenced records can publish.')}</ol>`;$('redownloadResearch').disabled=!lastRailExport;$('downloadCorrection').disabled=!lastRailFailures.length}
async function importResearchFileV2(file){const progress=$('railImportProgress'),steps=[],step=value=>{steps.push(value);progress.textContent=steps.join(' → ')};step('Reading completed research');const data=JSON.parse(await file.text());lastRailImport=data;step('Checking file and station identities');if(data.schema!==COMPLETED_SCHEMA||Number(data.version)!==SCHEMA_VERSION)throw Error(`Expected ${COMPLETED_SCHEMA} version ${SCHEMA_VERSION}.`);validateRequestedRecords(data,selected());const plan=currentRailPlan(),batch=(plan.batches||[]).find(x=>x.batchId===data.batchMetadata?.batchId),metadataCheck=TPTResearchWorkflow.validateBatchMetadata(batch,data.batchMetadata);if(!metadataCheck.valid)throw Error('Batch details do not match: '+metadataCheck.problems.join('; '));step('Checking evidence and required train frequencies');const reports=TPTResearchQuality.validateRailCompleted(data,{reject:false,allowLegacyEvidence:false}).records,failedNames=new Set(),failures=[];reports.forEach(report=>{if(!report.publishable){failedNames.add(report.record);report.publicationBlockers.forEach(issue=>{const raw=(data.records||[]).find(x=>(completedRecord(x).name||completedRecord(x).canonicalName)===report.record),field=completedRecord(raw||{}).fields?.[issue.field];failures.push({record:report.record,field:issue.field,reason:issue.reason,url:field?.source||field?.sources?.[0]?.url||''})})}});lastRailFailures=failures;const passing=(data.records||[]).filter(raw=>!failedNames.has(completedRecord(raw).name||completedRecord(raw).canonicalName)),failed=(data.records||[]).filter(raw=>failedNames.has(completedRecord(raw).name||completedRecord(raw).canonicalName));if(passing.length){step('Saving '+passing.length+' passing station(s)');const subset={...data,records:passing},partFile=new File([JSON.stringify(subset)],file.name,{type:'application/json'});await importJson(partFile,'research')}const passedKeys=passing.map(x=>TPTResearchWorkflow.railKey(completedRecord(x))),failedKeys=failed.map(x=>TPTResearchWorkflow.railKey(completedRecord(x)));TPTResearchWorkflow.markBatch(plan,batch.batchId,failed.length?'correction-required':'imported',file.name,{passedKeys,failedKeys,failureCount:failures.length});railPlan=plan;persistRailPlan();renderRailFailures();renderRailPlan();if(failed.length){step(`${passing.length} station(s) saved; ${failed.length} require correction`);progress.textContent+=' — Passing stations are preserved. Download the targeted correction request.'}else{lastRailFailures=[];renderRailFailures();step('Batch complete');progress.textContent+=` — ${passing.length} station(s) passed all required evidence and frequency checks.`}}
async function importRailCompatible(file){const data=JSON.parse(await file.text());if(data.batchMetadata)return importResearchFileV2(file);validateRequestedRecords(data,selected());const quality=TPTResearchQuality.validateRailCompleted(data,{reject:false,allowLegacyEvidence:data.researchQualityProfile!==TPTResearchQuality.build}),failedReports=quality.records.filter(report=>!report.publishable),failedNames=new Set(failedReports.map(report=>report.record)),passing=(data.records||[]).filter(raw=>!failedNames.has(completedRecord(raw).name||completedRecord(raw).canonicalName));if(!passing.length)throw Error('Rail file contains no station that passes current evidence and frequency requirements.');await importJson(new File([JSON.stringify({...data,records:passing})],file.name,{type:'application/json'}),'research');lastRailImport=data;lastRailFailures=failedReports.flatMap(report=>report.publicationBlockers.map(issue=>{const raw=(data.records||[]).find(x=>(completedRecord(x).name||completedRecord(x).canonicalName)===report.record),field=completedRecord(raw||{}).fields?.[issue.field];return{record:report.record,field:issue.field,reason:issue.reason,url:field?.source||field?.sources?.[0]?.url||''}}));renderRailFailures();$('railImportProgress').textContent=`Rail research imported for review: ${passing.length} of ${data.records.length} station(s) passed.${lastRailFailures.length?' Download one targeted correction request for the failed stations.':' No automatic publication occurred.'}`;renderRailPlan()}
$('importResearch').onchange=async e=>{try{if(e.target.files[0])await importRailCompatible(e.target.files[0]);if(lastRailFailures.length)localStorage.setItem(BATCH_KEY+'.correction',JSON.stringify({data:lastRailImport,failures:lastRailFailures}));else localStorage.removeItem(BATCH_KEY+'.correction')}catch(x){$('railImportProgress').textContent+=' — CORRECTION REQUIRED: '+x.message;show(x.message,true)}e.target.value=''};
$('railPrimaryAction').onclick=()=>{const action=$('railPrimaryAction').dataset.action;if(action==='export')exportResearch();else if(action==='import')$('importResearch').click();else if(action==='correction')correctionRequest();else if(action==='review')$('railProposalList').scrollIntoView({behavior:'smooth',block:'start'})};
$('redownloadResearch').onclick=()=>lastRailExport&&download(lastRailExport.name,JSON.stringify(lastRailExport.data,null,2));
$('downloadCorrection').onclick=correctionRequest;
$('railImportVisible').onclick=()=>$('importResearch').click();
$('bulkRailResearch').onclick=exportBulkRail;
document.querySelector('.tab[data-tab="research"]').addEventListener('click',renderRailPlan);
if(new URLSearchParams(location.search).get('tab')==='research')document.querySelector('.tab[data-tab="research"]').click();
$('fitAssessment').onclick=()=>{if(site&&stations.length)map.fitBounds([[site.lat,site.lon],...stations.map(s=>[s.lat,s.lon])]);else if(site)map.setView([site.lat,site.lon],15)};
$('returnSite').onclick=()=>site&&map.setView([site.lat,site.lon],16);
