window.addEventListener('beforeunload',event=>{if(Object.keys(localLibrary).length){event.preventDefault();event.returnValue=''}});document.querySelectorAll('a[href]').forEach(link=>link.addEventListener('click',event=>{if(Object.keys(localLibrary).length&&!confirm('Unpublished Rail proposals remain in this browser. Leave this module?'))event.preventDefault()}));
initMap();loadProject();updateKnowledge();renderSources();sharedStatus();renderRailPlan();sharedLoadPromise=refreshSharedRail();log('initialised',{build:BUILD,addressControls:true,researchExport:true,researchImport:true,safeBatchLimit:5,sharedPublishing:true,directSharedConsumption:true});
